package v1alpha

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/runtime/actor/v1alpha"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type HealthProxy struct {
	v1alpha.UnimplementedHealthServer
	client v1alpha.HealthClient
}

func init() {
	proxyutil.Register(&v1alpha.Health_ServiceDesc, NewHealthProxy)
}
func NewHealthProxy(cc grpc.ClientConnInterface) v1alpha.HealthServer {
	return &HealthProxy{client: v1alpha.NewHealthClient(cc)}
}
func (p *HealthProxy) Check(ctx context.Context, in *emptypb.Empty) (*v1alpha.HealthStatus, error) {
	return proxyutil.ProxyMethod[emptypb.Empty, v1alpha.HealthStatus](p.client.Check)(ctx, in)
}
